mapper.select:
SELECT * FROM t_expense
WHERE user_id = #{userId}
  AND deleted = 0
  AND category = #{category}
  AND occurred_at >= #{from}
  AND occurred_at <= #{to}
ORDER BY occurred_at DESC, id DESC
LIMIT #{offset}, #{size}

SELECT COUNT(*) FROM t_expense
WHERE user_id = #{userId}
  AND deleted = 0
  AND category = #{category}
  AND occurred_at >= #{from}
  AND occurred_at <= #{to}

SELECT category AS k, COALESCE(SUM(amount), 0) AS v
FROM t_expense
WHERE user_id = #{userId} AND deleted = 0
  AND occurred_at >= #{from}
  AND occurred_at <= #{to}
GROUP BY category

SELECT COALESCE(SUM(amount), 0) FROM t_expense
WHERE user_id = #{userId} AND deleted = 0
  AND occurred_at >= #{from}
  AND occurred_at <= #{to}

SELECT SUM(amount) FROM t_expense
WHERE user_id = #{userId} AND deleted = 0
  AND occurred_at >= #{from}
  AND occurred_at < #{to}

SELECT COUNT(*) FROM t_expense
WHERE user_id = #{userId}
  AND occurred_at >= #{dayStart}
  AND occurred_at <  #{nextDayStart}
  AND deleted = 0
